using Autodesk.Revit.DB;

// CORRECT: NewAlignment lives on FamilyItemFactory, accessed via doc.FamilyCreate.
// There is NO 'Alignment.Create' static method -- do not invent one.
using (Transaction tx = new Transaction(familyDoc, "Lock Face to Ref Plane"))
{
    tx.Start();

    // Look up the named reference plane
    ReferencePlane rpLeft = new FilteredElementCollector(familyDoc)
        .OfClass(typeof(ReferencePlane))
        .Cast<ReferencePlane>()
        .First(r => r.Name == "Left");

    // References must be computed when extracting from geometry
    Options opts = new Options();
    opts.ComputeReferences = true;
    opts.IncludeNonVisibleObjects = false;
    opts.View = familyDoc.ActiveView;

    // Walk extrusion geometry to find the face whose normal points to -X (left)
    Reference leftFaceRef = null;
    foreach (GeometryObject go in ext.get_Geometry(opts))
    {
        if (go is Solid solid)
        {
            foreach (Face face in solid.Faces)
            {
                PlanarFace pf = face as PlanarFace;
                if (pf != null && pf.FaceNormal.IsAlmostEqualTo(-XYZ.BasisX))
                {
                    leftFaceRef = pf.Reference;
                    break;
                }
            }
        }
    }

    if (leftFaceRef == null) throw new InvalidOperationException("Could not find left face reference");

    // NewAlignment(view, ref1, ref2) -- creates an alignment constraint AND locks it
    familyDoc.FamilyCreate.NewAlignment(familyDoc.ActiveView, rpLeft.GetReference(), leftFaceRef);

    tx.Commit();
}

using Autodesk.Revit.DB;

// Correct pattern: FamilyLabel is a settable property on Dimension.
// It throws InvalidOperationException if the dimension has fewer than 2 references
// or if the references aren't valid for labeling. There is NO 'IsReferencesValidForLabel' method.
using (Transaction tx = new Transaction(familyDoc, "Label Dimension with Parameter"))
{
    tx.Start();

    FamilyManager fm = familyDoc.FamilyManager;
    FamilyParameter pWidth = fm.get_Parameter("Width")
        ?? fm.AddParameter("Width", GroupTypeId.Geometry, SpecTypeId.Length, false);

    // Build a ReferenceArray from the two refs you want to dimension between
    ReferenceArray refs = new ReferenceArray();
    refs.Append(rpLeft.GetReference());
    refs.Append(rpRight.GetReference());

    // NewLinearDimension(view, line, refs)
    Line dimLine = Line.CreateBound(new XYZ(-2, 0, 0), new XYZ(2, 0, 0));
    Dimension dim = familyDoc.FamilyCreate.NewLinearDimension(familyDoc.ActiveView, dimLine, refs);

    // Bind the parameter to the dimension -- this is what makes it flex
    try
    {
        dim.FamilyLabel = pWidth;
    }
    catch (InvalidOperationException ex)
    {
        // Thrown when refs are not valid for labeling (e.g. only 1 ref, or a temp dim)
        throw new InvalidOperationException($"Cannot label dimension: {ex.Message}", ex);
    }

    tx.Commit();
}

using Autodesk.Revit.DB;

// IMPORTANT: Face.Reference is null unless geometry was retrieved with
// an Options where ComputeReferences = true. Without this, any downstream
// NewAlignment / NewDimension call that needs the reference will fail silently
// or throw NullReferenceException.

Options opts = new Options();
opts.ComputeReferences      = true;   // <-- THE critical flag
opts.IncludeNonVisibleObjects = false;
opts.View = familyDoc.ActiveView;     // View-specific references if needed

Reference faceRef = null;
foreach (GeometryObject go in extrusion.get_Geometry(opts))
{
    Solid solid = go as Solid;
    if (solid == null || solid.Faces.Size == 0) continue;

    foreach (Face face in solid.Faces)
    {
        PlanarFace pf = face as PlanarFace;
        if (pf == null) continue;
        if (pf.FaceNormal.IsAlmostEqualTo(XYZ.BasisX))
        {
            faceRef = pf.Reference;   // now non-null because ComputeReferences=true
            break;
        }
    }
}

if (faceRef == null) throw new InvalidOperationException(
    "No +X face found -- or ComputeReferences was not set on Options");

using Autodesk.Revit.DB;
using System.Linq;

using (Transaction tx = new Transaction(familyDoc, "Parametric Width Extrusion"))
{
    tx.Start();

    // 1. Declare the Width parameter
    FamilyManager fm = familyDoc.FamilyManager;
    FamilyParameter pWidth = fm.AddParameter("Width", GroupTypeId.Geometry, SpecTypeId.Length, false);
    fm.Set(pWidth, 1.0); // 1 foot default

    // 2. Look up the built-in Left and Right ref planes
    ReferencePlane rpLeft = new FilteredElementCollector(familyDoc)
        .OfClass(typeof(ReferencePlane)).Cast<ReferencePlane>()
        .First(r => r.Name == "Left");
    ReferencePlane rpRight = new FilteredElementCollector(familyDoc)
        .OfClass(typeof(ReferencePlane)).Cast<ReferencePlane>()
        .First(r => r.Name == "Right");

    // 3. Sketch plane on XY at origin
    SketchPlane sp = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));

    // 4. CLOSED rectangular profile -- all 4 lines, so CurveArray forms a loop
    double w = 1.0;   // initial value; the param binding below makes it flex
    double d = 0.5;
    CurveArrArray profile = new CurveArrArray();
    CurveArray loop = new CurveArray();
    loop.Append(Line.CreateBound(new XYZ(-w/2, -d/2, 0), new XYZ( w/2, -d/2, 0)));
    loop.Append(Line.CreateBound(new XYZ( w/2, -d/2, 0), new XYZ( w/2,  d/2, 0)));
    loop.Append(Line.CreateBound(new XYZ( w/2,  d/2, 0), new XYZ(-w/2,  d/2, 0)));
    loop.Append(Line.CreateBound(new XYZ(-w/2,  d/2, 0), new XYZ(-w/2, -d/2, 0))); // close
    profile.Append(loop);

    // 5. Extrusion
    Extrusion ext = familyDoc.FamilyCreate.NewExtrusion(true, profile, sp, 2.0);

    // 6. Get face references with ComputeReferences = true
    Options opts = new Options { ComputeReferences = true, View = familyDoc.ActiveView };
    Reference leftRef  = null, rightRef = null;
    foreach (GeometryObject go in ext.get_Geometry(opts))
    {
        if (!(go is Solid solid)) continue;
        foreach (Face f in solid.Faces)
        {
            if (!(f is PlanarFace pf)) continue;
            if (pf.FaceNormal.IsAlmostEqualTo(-XYZ.BasisX)) leftRef  = pf.Reference;
            if (pf.FaceNormal.IsAlmostEqualTo( XYZ.BasisX)) rightRef = pf.Reference;
        }
    }

    // 7. Align AND lock the left/right faces to the ref planes
    familyDoc.FamilyCreate.NewAlignment(familyDoc.ActiveView, rpLeft.GetReference(),  leftRef);
    familyDoc.FamilyCreate.NewAlignment(familyDoc.ActiveView, rpRight.GetReference(), rightRef);

    // 8. Dimension the ref planes and label with Width -- THIS is what drives the flex
    ReferenceArray refs = new ReferenceArray();
    refs.Append(rpLeft.GetReference());
    refs.Append(rpRight.GetReference());
    Dimension dim = familyDoc.FamilyCreate.NewLinearDimension(
        familyDoc.ActiveView,
        Line.CreateBound(new XYZ(-1, -1, 0), new XYZ(1, -1, 0)),
        refs);
    dim.FamilyLabel = pWidth;

    tx.Commit();
}

// 9. Verify flex: set Width to a different value and regenerate
using (Transaction tx2 = new Transaction(familyDoc, "Test Flex"))
{
    tx2.Start();
    familyDoc.FamilyManager.Set(familyDoc.FamilyManager.get_Parameter("Width"), 2.0);
    tx2.Commit();
}

`Dimension.FamilyLabel = param` throws `InvalidOperationException` when ANY of these are true:

1. The dimension has fewer than 2 references -- a single-reference dimension can't be labeled.
2. The dimension is equality-constrained (its Segments show 'EQ') -- EQ dimensions can't be labeled with a parameter.
3. The parameter's SpecTypeId does not match the dimension's measurement type (e.g. assigning a `Length` parameter to an angular dimension).
4. The dimension references are temporary / not committed (you dimensioned inside the same transaction before the elements committed).
5. The parameter is read-only (some shared parameters).

There is NO `IsReferencesValidForLabel()` method -- do not invent one. Validate by catching the exception:

```csharp
try
{
    dim.FamilyLabel = pWidth;
}
catch (InvalidOperationException ex)
{
    // Log the actual validity issue from ex.Message
    throw;
}
```

Alternative pre-check: `dim.References.Size >= 2 && dim.NumberOfSegments == 1` eliminates the two most common failure cases, but the exception is still authoritative.

