// Number (unitless)
FamilyParameter pNum = fm.AddParameter("Count",    GroupTypeId.Constraints, SpecTypeId.Int.Integer, false);
// Yes/No
FamilyParameter pBool = fm.AddParameter("Enabled", GroupTypeId.Visibility,  SpecTypeId.Boolean.YesNo, false);
// Text
FamilyParameter pTxt = fm.AddParameter("Note",     GroupTypeId.IdentityData, SpecTypeId.String.Text, false);

// Common GroupTypeId values:
//   GroupTypeId.Geometry, GroupTypeId.Constraints, GroupTypeId.Materials,
//   GroupTypeId.Graphics, GroupTypeId.Visibility, GroupTypeId.IdentityData,
//   GroupTypeId.Structural, GroupTypeId.Mechanical, GroupTypeId.Electrical,
//   GroupTypeId.Plumbing, GroupTypeId.Text

using Autodesk.Revit.DB;

// Pattern 1: `using` block -- auto-rolls back on any uncaught exception.
using (Transaction tx = new Transaction(familyDoc, "Create Parametric Extrusion"))
{
    TransactionStatus status = tx.Start();
    if (status != TransactionStatus.Started)
        throw new InvalidOperationException($"Could not start transaction: {status}");

    try
    {
        // ... all your Create/Modify calls here ...

        tx.Commit();
    }
    catch
    {
        if (tx.HasStarted() && !tx.HasEnded())
            tx.RollBack();
        throw;
    }
}

// Pattern 2: nested sub-transactions (for multi-phase work where part of the
// scope is fine to keep even if later steps fail).
using (Transaction outer = new Transaction(familyDoc, "Build Family"))
{
    outer.Start();
    using (SubTransaction sub = new SubTransaction(familyDoc))
    {
        sub.Start();
        // ... step 1 ...
        sub.Commit();
    }
    using (SubTransaction sub = new SubTransaction(familyDoc))
    {
        sub.Start();
        // ... step 2 ...
        sub.Commit();
    }
    outer.Commit();
}

// Rules:
// 1. Never call Create/Modify APIs outside a started transaction -- throws.
// 2. Name every transaction -- shows in undo history.
// 3. Don't keep a Transaction open across async/await boundaries.
// 4. Don't try to nest raw Transactions -- use SubTransaction for nesting.
// 5. For unattended headless runs, register an IFailuresPreprocessor to auto-resolve warnings.

using Autodesk.Revit.DB;
using System.Linq;

// In a standard generic family template the canonical ref plane names are:
//   "Center (Left/Right)", "Center (Front/Back)", "Left", "Right", "Front", "Back"
// Some templates also include "Reference Level" (a level, not a ref plane).

static ReferencePlane GetRefPlaneByName(Document familyDoc, string name)
{
    ReferencePlane rp = new FilteredElementCollector(familyDoc)
        .OfClass(typeof(ReferencePlane))
        .Cast<ReferencePlane>()
        .FirstOrDefault(r => r.Name == name);
    if (rp == null)
        throw new InvalidOperationException($"Reference plane '{name}' not found in family");
    return rp;
}

// Usage:
ReferencePlane rpLeft   = GetRefPlaneByName(familyDoc, "Left");
ReferencePlane rpRight  = GetRefPlaneByName(familyDoc, "Right");
ReferencePlane rpCenter = GetRefPlaneByName(familyDoc, "Center (Left/Right)");

// To CREATE a new named reference plane (when the template doesn't have the one you need):
using (Transaction tx = new Transaction(familyDoc, "Add Ref Plane"))
{
    tx.Start();
    ReferencePlane rpNew = familyDoc.FamilyCreate.NewReferencePlane(
        new XYZ(0, 1, 0),   // bubble end
        new XYZ(0, 0, 0),   // free end
        XYZ.BasisZ,         // cut vector
        familyDoc.ActiveView);
    rpNew.Name = "Working Plane 1";
    tx.Commit();
}

using Autodesk.Revit.DB;

// The `end` argument of NewExtrusion(isSolid, profile, sketchPlane, end) is a one-time LITERAL.
// The extrusion's flexing comes from aligning its top/bottom FACES to labeled ref planes,
// not from re-passing end. Same pattern as Width: make a ref plane, align the face, label a
// dimension that separates the origin from the ref plane, bind the param to the dimension.

using (Transaction tx = new Transaction(familyDoc, "Parametric Depth Extrusion"))
{
    tx.Start();

    FamilyManager fm = familyDoc.FamilyManager;
    FamilyParameter pDepth = fm.AddParameter("Depth", GroupTypeId.Geometry, SpecTypeId.Length, false);
    fm.Set(pDepth, 1.0);

    // Create a ref plane at Z = 1.0 (the initial top of the extrusion)
    ReferencePlane rpTop = familyDoc.FamilyCreate.NewReferencePlane(
        new XYZ(1, 0, 1.0),   // bubble end, at desired Z
        new XYZ(0, 0, 1.0),   // free end
        XYZ.BasisY,            // cut vector (perpendicular to plane normal)
        familyDoc.ActiveView);
    rpTop.Name = "Top";

    // Built-in origin ref plane (the sketch plane at Z=0)
    ReferencePlane rpBottom = new FilteredElementCollector(familyDoc)
        .OfClass(typeof(ReferencePlane)).Cast<ReferencePlane>()
        .First(r => r.Name == "Reference Level" || r.Name == "Center (Front/Back)");

    // Create the extrusion (end literal matches the ref plane's initial Z)
    SketchPlane sp = SketchPlane.Create(familyDoc, Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));
    CurveArrArray profile = new CurveArrArray();
    CurveArray loop = new CurveArray();
    loop.Append(Line.CreateBound(new XYZ(-0.5, -0.5, 0), new XYZ( 0.5, -0.5, 0)));
    loop.Append(Line.CreateBound(new XYZ( 0.5, -0.5, 0), new XYZ( 0.5,  0.5, 0)));
    loop.Append(Line.CreateBound(new XYZ( 0.5,  0.5, 0), new XYZ(-0.5,  0.5, 0)));
    loop.Append(Line.CreateBound(new XYZ(-0.5,  0.5, 0), new XYZ(-0.5, -0.5, 0)));
    profile.Append(loop);
    Extrusion ext = familyDoc.FamilyCreate.NewExtrusion(true, profile, sp, 1.0);

    // Find the top (+Z) face reference
    Options opts = new Options { ComputeReferences = true, View = familyDoc.ActiveView };
    Reference topRef = null;
    foreach (GeometryObject go in ext.get_Geometry(opts))
        if (go is Solid solid)
            foreach (Face f in solid.Faces)
                if (f is PlanarFace pf && pf.FaceNormal.IsAlmostEqualTo(XYZ.BasisZ))
                    topRef = pf.Reference;

    // Align the top face to the Top ref plane
    familyDoc.FamilyCreate.NewAlignment(familyDoc.ActiveView, rpTop.GetReference(), topRef);

    // Dimension from bottom plane to top plane, label with Depth
    ReferenceArray refs = new ReferenceArray();
    refs.Append(rpBottom.GetReference());
    refs.Append(rpTop.GetReference());
    Dimension dim = familyDoc.FamilyCreate.NewLinearDimension(
        familyDoc.ActiveView,
        Line.CreateBound(new XYZ(2, 0, 0), new XYZ(2, 0, 1.0)),
        refs);
    dim.FamilyLabel = pDepth;

    tx.Commit();
}

using Autodesk.Revit.DB;

static bool TestFlex(Document familyDoc, string paramName, double newValue)
{
    FamilyManager fm = familyDoc.FamilyManager;
    FamilyParameter param = fm.get_Parameter(paramName);
    if (param == null)
        throw new InvalidOperationException($"Parameter {paramName} not found");
    if (param.IsReporting)
        throw new InvalidOperationException($"{paramName} is a reporting parameter -- cannot Set");

    // Capture geometry bounding box before
    FamilyType currentType = fm.CurrentType;
    if (currentType == null)
    {
        // Family has no types defined -- create a default one
        using (Transaction t = new Transaction(familyDoc, "Add default type")) {
            t.Start();
            fm.NewType("Default");
            t.Commit();
        }
        currentType = fm.CurrentType;
    }

    // Set the new value and regenerate
    using (Transaction t = new Transaction(familyDoc, $"Flex {paramName}"))
    {
        t.Start();
        fm.Set(param, newValue);
        familyDoc.Regenerate();   // force geometry recomputation
        t.Commit();
    }

    // Check: if the regenerate fails silently (constraints over-constrained),
    // Revit reports warnings rather than throwing. Query the document warnings.
    var warnings = familyDoc.GetWarnings();
    foreach (var w in warnings)
    {
        string desc = w.GetDescriptionText();
        if (desc.Contains("Constraints are not satisfied") || desc.Contains("overconstrained"))
            return false;   // Flex failed -- geometry couldn't adjust
    }

    return true;
}

// Usage:
bool widthFlexed = TestFlex(familyDoc, "Width", 2.5);
bool depthFlexed = TestFlex(familyDoc, "Depth", 3.0);

using Autodesk.Revit.DB;

// There are TWO methods on FamilyItemFactory for dimensions:
//
// 1. NewLinearDimension(View view, Line line, ReferenceArray refs)
//    - Use for 2+ parallel or collinear references
//    - Creates a single linear segment (or equality-constrained chain if refs > 2)
//
// 2. NewDimension(View view, Line line, ReferenceArray refs, DimensionType dimType)
//    - Same signature + an explicit DimensionType (style)
//    - Use when you want a specific dimension style applied (e.g. imperial vs. metric)
//
// There is ALSO NewDiameterDimension, NewRadialDimension, NewAngularDimension,
// NewArcLengthDimension -- use these for non-linear dimension types.

using (Transaction tx = new Transaction(familyDoc, "Create Dimensions"))
{
    tx.Start();

    ReferenceArray refs = new ReferenceArray();
    refs.Append(rpLeft.GetReference());
    refs.Append(rpRight.GetReference());

    // Simple linear dim (default style):
    Dimension dimA = familyDoc.FamilyCreate.NewLinearDimension(
        familyDoc.ActiveView,
        Line.CreateBound(new XYZ(-1, -1, 0), new XYZ(1, -1, 0)),
        refs);

    // With an explicit dimension type (for style control):
    DimensionType linearType = new FilteredElementCollector(familyDoc)
        .OfClass(typeof(DimensionType)).Cast<DimensionType>()
        .First(dt => dt.StyleType == DimensionStyleType.Linear);
    Dimension dimB = familyDoc.FamilyCreate.NewDimension(
        familyDoc.ActiveView,
        Line.CreateBound(new XYZ(-1, -2, 0), new XYZ(1, -2, 0)),
        refs,
        linearType);

    // Radial/diameter for a cylinder:
    // Dimension r = familyDoc.FamilyCreate.NewRadialDimension(view, arcFaceRef, dimLine);

    tx.Commit();
}
